changeSet.sql:
CREATE TABLE nexus.chunks_384 ( tenant_id TEXT NOT NULL, collection TEXT NOT NULL, chash TEXT NOT NULL, chunk_text TEXT NOT NULL, embedding vector(384) NOT NULL, chunk_tsv tsvector GENERATED ALWAYS AS (to_tsvector('english', chunk_text)) STORED, metadata JSONB, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), CONSTRAINT chunks_384_pk PRIMARY KEY (tenant_id, collection, chash) );
-- HNSW index for approximate nearest-neighbour cosine search CREATE INDEX idx_chunks_384_embedding ON nexus.chunks_384 USING hnsw (embedding vector_cosine_ops) WITH (m = 16, ef_construction = 64);
-- GIN index on tsvector for Phase 3 hybrid FTS CREATE INDEX idx_chunks_384_tsv ON nexus.chunks_384 USING GIN (chunk_tsv);

CREATE TABLE nexus.chunks_768 ( tenant_id TEXT NOT NULL, collection TEXT NOT NULL, chash TEXT NOT NULL, chunk_text TEXT NOT NULL, embedding vector(768) NOT NULL, chunk_tsv tsvector GENERATED ALWAYS AS (to_tsvector('english', chunk_text)) STORED, metadata JSONB, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), CONSTRAINT chunks_768_pk PRIMARY KEY (tenant_id, collection, chash) );
-- HNSW index for approximate nearest-neighbour cosine search CREATE INDEX idx_chunks_768_embedding ON nexus.chunks_768 USING hnsw (embedding vector_cosine_ops) WITH (m = 16, ef_construction = 64);
-- GIN index on tsvector for Phase 3 hybrid FTS CREATE INDEX idx_chunks_768_tsv ON nexus.chunks_768 USING GIN (chunk_tsv);

CREATE TABLE nexus.chunks_1024 ( tenant_id TEXT NOT NULL, collection TEXT NOT NULL, chash TEXT NOT NULL, chunk_text TEXT NOT NULL, embedding vector(1024) NOT NULL, chunk_tsv tsvector GENERATED ALWAYS AS (to_tsvector('english', chunk_text)) STORED, metadata JSONB, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), CONSTRAINT chunks_1024_pk PRIMARY KEY (tenant_id, collection, chash) );
-- HNSW index for approximate nearest-neighbour cosine search CREATE INDEX idx_chunks_1024_embedding ON nexus.chunks_1024 USING hnsw (embedding vector_cosine_ops) WITH (m = 16, ef_construction = 64);
-- GIN index on tsvector for Phase 3 hybrid FTS CREATE INDEX idx_chunks_1024_tsv ON nexus.chunks_1024 USING GIN (chunk_tsv);

-- chunks_384
ALTER TABLE nexus.chunks_384 ENABLE ROW LEVEL SECURITY;
ALTER TABLE nexus.chunks_384 FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON nexus.chunks_384
    USING      (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));

-- chunks_768
ALTER TABLE nexus.chunks_768 ENABLE ROW LEVEL SECURITY;
ALTER TABLE nexus.chunks_768 FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON nexus.chunks_768
    USING      (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));

-- chunks_1024
ALTER TABLE nexus.chunks_1024 ENABLE ROW LEVEL SECURITY;
ALTER TABLE nexus.chunks_1024 FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON nexus.chunks_1024
    USING      (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));

changeSet.rollback:
DROP POLICY IF EXISTS tenant_isolation ON nexus.chunks_1024;
ALTER TABLE nexus.chunks_1024 NO FORCE ROW LEVEL SECURITY;
ALTER TABLE nexus.chunks_1024 DISABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS tenant_isolation ON nexus.chunks_768;
ALTER TABLE nexus.chunks_768 NO FORCE ROW LEVEL SECURITY;
ALTER TABLE nexus.chunks_768 DISABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS tenant_isolation ON nexus.chunks_384;
ALTER TABLE nexus.chunks_384 NO FORCE ROW LEVEL SECURITY;
ALTER TABLE nexus.chunks_384 DISABLE ROW LEVEL SECURITY;

changeSet.sql:
ALTER TABLE nexus.catalog_document_chunks
    ADD COLUMN IF NOT EXISTS collection TEXT;

-- Index for collection-scoped manifest lookups used by VectorRepository write path
CREATE INDEX idx_catalog_chunks_collection
    ON nexus.catalog_document_chunks (tenant_id, collection)
    WHERE collection IS NOT NULL;
